// --- SinhalaSTT engine (ported from font_converter.py) -----------------------
function _trim(s) { return String(s).replace(/^\s+/, "").replace(/\s+$/, ""); }

function containsSinhala(text) {
  for (var i = 0; i < text.length; i++) {
    var c = text.charCodeAt(i);
    if (c >= 0x0D80 && c <= 0x0DFF) return true;
  }
  return false;
}

function _protectAscii(text) {
  var values = [];
  var re = /[A-Za-z0-9]+(?:[._-][A-Za-z0-9]+)*/g;
  var out = text.replace(re, function (m) {
    values.push(m);
    return "\uE000" + (values.length - 1) + "\uE001";
  });
  return { text: out, values: values };
}

function _restoreAscii(text, values) {
  for (var i = 0; i < values.length; i++) {
    text = text.split("\uE000" + i + "\uE001").join(values[i]);
  }
  return text;
}

function unicodeToFM(text) {
  var p = _protectAscii(text);
  var converted = p.text;
  for (var i = 0; i < FM_RULES.length; i++) {
    converted = converted.split(FM_RULES[i][0]).join(FM_RULES[i][1]);
  }
  converted = _restoreAscii(converted, p.values);
  converted = converted.split("\u200D").join("").split("\u200B").join("");
  return converted;
}

function splitToLines(text, mode) {
  var paras = String(text).split(/(?:\r?\n\s*){2,}/);
  var out = [];
  for (var pi = 0; pi < paras.length; pi++) {
    var norm = _trim(paras[pi].replace(/\s+/g, " "));
    if (!norm) continue;
    if (mode === "sentence") {
      var parts = norm.match(/[^.!?\u0964]+[.!?\u0964]*/g);
      if (!parts) parts = [norm];
      for (var s = 0; s < parts.length; s++) {
        var t = _trim(parts[s]);
        if (t) out.push(t);
      }
    } else {
      var n = parseInt(mode, 10);
      if (!n || n < 1) n = 1;
      var words = norm.split(/\s+/);
      var group = [];
      for (var w = 0; w < words.length; w++) {
        if (words[w] === "") continue;
        group.push(words[w]);
        if (group.length === n) { out.push(group.join(" ")); group = []; }
      }
      if (group.length) out.push(group.join(" "));
    }
  }
  return out;
}

if (typeof module !== "undefined" && module.exports) {
  module.exports = { containsSinhala: containsSinhala, unicodeToFM: unicodeToFM, splitToLines: splitToLines };
}
